import{c as a,Q as n,j as t,m as o}from"./chunks/framework.CBiVa4O3.js";const h=JSON.parse('{"title":"ZAB 与 EPaxos","description":"","frontmatter":{},"headers":[],"relativePath":"../distributedLearning/14-ZAB与EPaxos.md","filePath":"../distributedLearning/14-ZAB与EPaxos.md","lastUpdated":1778496697000}'),e={name:"../distributedLearning/14-ZAB与EPaxos.md"};function r(p,s,l,i,d,g){return n(),t("div",null,[...s[0]||(s[0]=[o(`<h1 id="zab-与-epaxos" tabindex="-1">ZAB 与 EPaxos <a class="header-anchor" href="#zab-与-epaxos" aria-label="Permalink to &quot;ZAB 与 EPaxos&quot;">​</a></h1><p>Raft 的胜利不等于共识协议的终点。这一篇讲两个<strong>与 Raft 同时代、解决稍微不同问题</strong>的协议:<strong>ZAB(ZooKeeper Atomic Broadcast)<strong>和</strong>EPaxos(Egalitarian Paxos)</strong>。<strong>ZAB 在 Raft 出生前 5 年就已经在 ZooKeeper 里跑了</strong>——它解决的不是&quot;通用日志复制&quot;,而是**&quot;严格 FIFO 顺序广播&quot;**,所以它有个 Raft 没有的关键特征:<strong>客户端顺序保证</strong>。<strong>EPaxos 是学术上的明珠</strong>——它打破了&quot;必须有 Leader&quot;的传统,<strong>任何节点都能发起共识</strong>,在跨地域写均匀的场景下理论延迟最优,<strong>但工业界用得极少</strong>——为什么?这一篇讲清楚。</p><blockquote><p>一句话先记住:<strong>ZAB = Raft 的前辈,加上严格 FIFO + 类 term 的 epoch + 三阶段(Discovery / Sync / Broadcast)</strong>,<strong>给 ZooKeeper 喂出了 sequential consistency,sync 才升级到 linearizable</strong>;<strong>EPaxos = 无 leader Paxos</strong>,<strong>冲突检测决定 1 RTT 还是 2 RTT</strong>,<strong>多地域写均匀的理论王者,工业落地极少——实现复杂、运维难、Raft 已经够用</strong>。<strong>选型上:强 leader 单地域用 Raft / Multi-Paxos;严格 FIFO 协调服务用 ZAB;多地域写均匀且实在装得起的用 EPaxos——但 99% 的人选不到第三档</strong>。</p></blockquote><hr><h2 id="一、为什么不是-raft-一统天下" tabindex="-1">一、为什么不是 Raft 一统天下 <a class="header-anchor" href="#一、为什么不是-raft-一统天下" aria-label="Permalink to &quot;一、为什么不是 Raft 一统天下&quot;">​</a></h2><p>Raft 在大部分场景已经够用,但有两类需求 Raft 不太擅长:</p><h3 id="_1-1-严格的-fifo-客户端顺序" tabindex="-1">1.1 严格的 FIFO 客户端顺序 <a class="header-anchor" href="#_1-1-严格的-fifo-客户端顺序" aria-label="Permalink to &quot;1.1 严格的 FIFO 客户端顺序&quot;">​</a></h3><p>Raft 保证<strong>多数派看到的日志顺序一致</strong>,但<strong>不强制保证同一客户端的请求按发送顺序进入日志</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client 先发 A,后发 B</span></span>
<span class="line"><span>Leader 同时收到 A 和 B(网络乱序),把 B 先放进日志,A 后放</span></span>
<span class="line"><span>Raft 视角:OK,日志一致就行</span></span>
<span class="line"><span>ZK / ZAB 视角:不行!必须 A 在 B 前面</span></span></code></pre></div><p><strong>ZooKeeper 用作分布式协调服务</strong>——配置中心、leader election、锁、序号分配,<strong>它的 API 语义本质上是&quot;对一个共享文件树的有序操作&quot;</strong>,<strong>客户端的操作顺序必须保留</strong>(<code>/parent → child1 → child2</code> 不能乱)。</p><p>ZAB 把这个语义<strong>直接做进协议</strong>:<strong>同一 client 的所有事务严格按发送顺序进入提交序列</strong>。</p><h3 id="_1-2-多地域写均匀-leader-不是瓶颈也是延迟" tabindex="-1">1.2 多地域写均匀:Leader 不是瓶颈也是延迟 <a class="header-anchor" href="#_1-2-多地域写均匀-leader-不是瓶颈也是延迟" aria-label="Permalink to &quot;1.2 多地域写均匀:Leader 不是瓶颈也是延迟&quot;">​</a></h3><p>Raft 强 leader 意味着:<strong>所有写都要先到 leader,再 RTT 到多数派</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>3 地域 5 节点:北京、上海、广州、东京、新加坡</span></span>
<span class="line"><span>leader 在北京</span></span>
<span class="line"><span></span></span>
<span class="line"><span>广州的 client 写一个 key:</span></span>
<span class="line"><span>    client → 广州本地节点 → 转发到北京 leader(40ms)</span></span>
<span class="line"><span>    leader 写 → 复制到次远的多数派(40ms)</span></span>
<span class="line"><span>    总计:80ms 起步</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果 leader 在上海,广州 client 写:</span></span>
<span class="line"><span>    client → 上海 leader(30ms) → 复制(30ms)</span></span>
<span class="line"><span>    总计:60ms</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果完全无 leader,广州 client 可以直接发起共识:</span></span>
<span class="line"><span>    client → 本地节点(0ms) → 直接联系其他节点(30-40ms)</span></span>
<span class="line"><span>    总计:30-40ms</span></span></code></pre></div><p><strong>EPaxos 的卖点就是这个</strong>——<strong>无 leader,每个 client 找最近的节点发起共识</strong>,理论上跨地域延迟最优。</p><hr><h2 id="二、zab-zookeeper-的原子广播" tabindex="-1">二、ZAB:ZooKeeper 的原子广播 <a class="header-anchor" href="#二、zab-zookeeper-的原子广播" aria-label="Permalink to &quot;二、ZAB:ZooKeeper 的原子广播&quot;">​</a></h2><p>ZAB 全称 <strong>ZooKeeper Atomic Broadcast</strong>,由 Flavio Junqueira 等人在 2008 设计、2011 完整描述(<em>Zab: High-performance broadcast for primary-backup systems</em>)。<strong>它跟 Raft 的关系是&quot;远房表亲&quot;——同样的安全性目标,不同的语义优先级</strong>。</p><h3 id="_2-1-核心数据结构-zxid" tabindex="-1">2.1 核心数据结构:zxid <a class="header-anchor" href="#_2-1-核心数据结构-zxid" aria-label="Permalink to &quot;2.1 核心数据结构:zxid&quot;">​</a></h3><p>ZAB 用一个 64 位整数 <strong>zxid</strong> 标识每个事务:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────┬────────────────┐</span></span>
<span class="line"><span>│  epoch (32位)  │ counter (32位)  │</span></span>
<span class="line"><span>└────────────────┴────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>epoch  = &quot;任期&quot;,每次 leader 切换 +1(类似 Raft 的 term)</span></span>
<span class="line"><span>counter= 该 epoch 内事务的递增编号</span></span></code></pre></div><p><strong>zxid 是全局单调递增的</strong>——比较两个 zxid:</p><ul><li>epoch 大者新</li><li>epoch 相同,counter 大者新</li></ul><p><strong>zxid 同时编码了顺序和合法性</strong>——这是 ZAB 和 Raft 一个微妙的区别,Raft 用(term, index)两个字段,ZAB 用一个 64 位整数。</p><h3 id="_2-2-三阶段流程" tabindex="-1">2.2 三阶段流程 <a class="header-anchor" href="#_2-2-三阶段流程" aria-label="Permalink to &quot;2.2 三阶段流程&quot;">​</a></h3><p>ZAB 把生命周期分成<strong>三个明确阶段</strong>(论文叫 phases):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                ┌───────────────────┐</span></span>
<span class="line"><span>                │  阶段 1: Discovery │</span></span>
<span class="line"><span>                │  发现集群中最大 zxid │</span></span>
<span class="line"><span>                │  选出 prospective  │</span></span>
<span class="line"><span>                │  leader            │</span></span>
<span class="line"><span>                └─────────┬─────────┘</span></span>
<span class="line"><span>                          │</span></span>
<span class="line"><span>                          ▼</span></span>
<span class="line"><span>                ┌───────────────────┐</span></span>
<span class="line"><span>                │  阶段 2: Sync     │</span></span>
<span class="line"><span>                │  把 leader 的日志   │</span></span>
<span class="line"><span>                │  同步到所有 follower│</span></span>
<span class="line"><span>                └─────────┬─────────┘</span></span>
<span class="line"><span>                          │</span></span>
<span class="line"><span>                          ▼</span></span>
<span class="line"><span>                ┌───────────────────┐</span></span>
<span class="line"><span>                │  阶段 3: Broadcast │</span></span>
<span class="line"><span>                │  对外服务,两阶段广播│</span></span>
<span class="line"><span>                │  (Propose → Ack    │</span></span>
<span class="line"><span>                │   → Commit)        │</span></span>
<span class="line"><span>                └─────────┬─────────┘</span></span>
<span class="line"><span>                          │</span></span>
<span class="line"><span>              leader 挂 / 失联 / 多数派失联</span></span>
<span class="line"><span>                          │</span></span>
<span class="line"><span>                          ▼</span></span>
<span class="line"><span>                  返回阶段 1,重选</span></span></code></pre></div><h4 id="阶段-1-discovery-发现" tabindex="-1">阶段 1:Discovery(发现) <a class="header-anchor" href="#阶段-1-discovery-发现" aria-label="Permalink to &quot;阶段 1:Discovery(发现)&quot;">​</a></h4><ul><li>节点互相交换自己见过的最大 zxid</li><li><strong>拥有最大 zxid 的节点</strong>成为 prospective leader(准 leader)</li><li>选出新 epoch(比集群已知的最大 epoch +1)</li><li>类比 Raft:相当于 RequestVote,只投票给&quot;日志最新&quot;的人</li></ul><h4 id="阶段-2-synchronization-同步" tabindex="-1">阶段 2:Synchronization(同步) <a class="header-anchor" href="#阶段-2-synchronization-同步" aria-label="Permalink to &quot;阶段 2:Synchronization(同步)&quot;">​</a></h4><ul><li>准 leader 把自己的日志发给所有 follower</li><li>Follower 截掉与 leader 不一致的尾部,补齐 leader 的日志</li><li>多数派同步完成后,准 leader 升级为正式 leader</li></ul><h4 id="阶段-3-broadcast-广播" tabindex="-1">阶段 3:Broadcast(广播) <a class="header-anchor" href="#阶段-3-broadcast-广播" aria-label="Permalink to &quot;阶段 3:Broadcast(广播)&quot;">​</a></h4><p>正常服务阶段,<strong>两阶段提交</strong>(注意:不是 2PC 那种带 prepare 的,是简化的两阶段):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Leader                Follower 1         Follower 2</span></span>
<span class="line"><span>  │                       │                  │</span></span>
<span class="line"><span>  │── Propose(txn) ──────▶│                  │</span></span>
<span class="line"><span>  │── Propose(txn) ──────────────────────────▶│</span></span>
<span class="line"><span>  │                       │                  │</span></span>
<span class="line"><span>  │                       │ append to log    │</span></span>
<span class="line"><span>  │                       │ (未 commit)       │</span></span>
<span class="line"><span>  │                       │                  │</span></span>
<span class="line"><span>  │◀───── ACK ────────────│                  │</span></span>
<span class="line"><span>  │◀───── ACK ────────────────────────────────│</span></span>
<span class="line"><span>  │                       │                  │</span></span>
<span class="line"><span>  │ majority ack          │                  │</span></span>
<span class="line"><span>  │ commit local          │                  │</span></span>
<span class="line"><span>  │                       │                  │</span></span>
<span class="line"><span>  │── Commit ────────────▶│                  │</span></span>
<span class="line"><span>  │── Commit ─────────────────────────────────│</span></span>
<span class="line"><span>  │                       │ apply            │</span></span>
<span class="line"><span>  │                       │                  │ apply</span></span></code></pre></div><p><strong>跟 Raft 的差别</strong>:</p><ul><li><strong>ZAB 显式发 Commit 消息</strong>,Raft 是把 commitIndex 搭在下次 AppendEntries 里</li><li>ZAB 的 Propose <strong>严格按 zxid 顺序</strong>——leader 内部维护单线程提议队列,<strong>任何乱序都不会发生</strong></li></ul><hr><h3 id="_2-3-zab-的-fifo-顺序保证-关键差异" tabindex="-1">2.3 ZAB 的 FIFO 顺序保证(关键差异) <a class="header-anchor" href="#_2-3-zab-的-fifo-顺序保证-关键差异" aria-label="Permalink to &quot;2.3 ZAB 的 FIFO 顺序保证(关键差异)&quot;">​</a></h3><p><strong>ZAB 给客户端的承诺</strong>:</p><ol><li><strong>写顺序保证</strong>:同一 client 的所有写,<strong>全局按发送顺序生效</strong></li><li><strong>读看到自己的写</strong>:client 自己发的写,<strong>自己后续的读一定能看到</strong>(read-your-writes)</li><li><strong>单调读</strong>:同一 client 后续的读看到的版本只增不减</li></ol><p><strong>实现机制</strong>:</p><ul><li>Client 通过 TCP 长连接连一个 server(follower 或 leader)</li><li>写请求经 follower 转发到 leader,<strong>但 client 端的请求 id 严格递增,server 不接受乱序请求</strong></li><li>Leader 在自己的提议队列里<strong>保留 client 的请求顺序</strong></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client 顺序发 A, B, C</span></span>
<span class="line"><span>即使网络让 B 先到 server,server 也会等 A 到了再处理 A,然后 B,然后 C</span></span></code></pre></div><blockquote><p><strong>这是 ZAB 比 Raft 多出来的语义</strong>。Raft 库默认不保证这一点,<strong>应用层要自己做 client-side sequencing</strong>(给请求带 client-id + sequence 号)。<strong>ZooKeeper 把这套做进协议,所以 ZK 客户端用起来像在单机操作文件</strong>。</p></blockquote><h3 id="_2-4-zk-的一致性级别-sequential-by-default-linearizable-on-sync" tabindex="-1">2.4 ZK 的一致性级别:Sequential by default,Linearizable on sync() <a class="header-anchor" href="#_2-4-zk-的一致性级别-sequential-by-default-linearizable-on-sync" aria-label="Permalink to &quot;2.4 ZK 的一致性级别:Sequential by default,Linearizable on sync()&quot;">​</a></h3><p><strong>这是被误解最多的一点</strong>:</p><table tabindex="0"><thead><tr><th>操作</th><th>一致性</th></tr></thead><tbody><tr><td><strong>写</strong>(create / setData / delete)</td><td><strong>Linearizable</strong>(所有写都过 leader + 多数派)</td></tr><tr><td><strong>默认读</strong></td><td><strong>Sequential</strong>(读 follower,可能落后)</td></tr><tr><td><strong>sync() 后读</strong></td><td><strong>Linearizable</strong>(强制 follower 追上 leader)</td></tr></tbody></table><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client A:setData(&quot;/x&quot;, &quot;v2&quot;)</span></span>
<span class="line"><span>        服务端返回 OK(已 commit)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Client B:getData(&quot;/x&quot;)</span></span>
<span class="line"><span>        如果 B 连的 follower 还没收到 commit</span></span>
<span class="line"><span>        B 可能读到 v1(旧值)</span></span></code></pre></div><p><strong>这不是 bug,这是 ZK 设计</strong>——<strong>ZK 默认 sequential 而非 linearizable</strong>,这是它高读吞吐的关键。<strong>需要强一致读的场景必须调 <code>sync()</code>,sync() 会强制 follower 跟 leader 同步后再返回</strong>。</p><blockquote><p><strong>常见踩坑</strong>:<strong>用 ZK 实现分布式锁,持锁判定用普通 getData,刚获锁的人可能读到旧的&quot;锁节点不存在&quot;状态——以为没人持锁</strong>。<strong>必须 sync() 或者用 watch 等待事件</strong>。</p></blockquote><hr><h3 id="_2-5-zab-vs-raft-详细对比" tabindex="-1">2.5 ZAB vs Raft 详细对比 <a class="header-anchor" href="#_2-5-zab-vs-raft-详细对比" aria-label="Permalink to &quot;2.5 ZAB vs Raft 详细对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>ZAB</th><th>Raft</th></tr></thead><tbody><tr><td><strong>任期标识</strong></td><td>epoch(32位)</td><td>term(64位)</td></tr><tr><td><strong>日志标识</strong></td><td>zxid = epoch + counter</td><td>(term, index)</td></tr><tr><td><strong>选 leader 规则</strong></td><td>zxid 最大者当选</td><td>(lastLogTerm, lastLogIndex) 最大者当选</td></tr><tr><td><strong>客户端顺序</strong></td><td><strong>严格 FIFO</strong>,协议保证</td><td><strong>不保证</strong>,应用自己做</td></tr><tr><td><strong>日志同步</strong></td><td>显式 Sync 阶段,leader 主动推</td><td>集成在 AppendEntries,prevLogIndex 协商</td></tr><tr><td><strong>Commit 通知</strong></td><td>单独 Commit 消息</td><td>commitIndex 搭次 AppendEntries</td></tr><tr><td><strong>成员变更</strong></td><td><strong>后期加,不优雅</strong>(ZK 3.5 reconfig)</td><td>论文原生支持 Joint Consensus + 单步</td></tr><tr><td><strong>快照</strong></td><td>snapshot + 事务日志分离</td><td>snapshot + log,InstallSnapshot RPC</td></tr><tr><td><strong>核心场景</strong></td><td>协调服务</td><td>通用日志复制</td></tr><tr><td><strong>典型系统</strong></td><td>ZooKeeper</td><td>etcd / Consul / TiKV</td></tr></tbody></table><blockquote><p><strong>不要纠结&quot;哪个更好&quot;</strong>——<strong>ZAB 是 ZK 量身定做的,Raft 是通用日志复制的标准库</strong>。<strong>如果你不是在写 ZK,别选 ZAB</strong>。但<strong>理解 ZAB 让你理解 ZK 的所有诡异行为</strong>——sync() / watch / sequential 节点的 zxid 顺序、leader 切换时为什么有时会&quot;丢&quot;watch 事件,全靠这一层。</p></blockquote><hr><h2 id="三、epaxos-无-leader-的-paxos" tabindex="-1">三、EPaxos:无 Leader 的 Paxos <a class="header-anchor" href="#三、epaxos-无-leader-的-paxos" aria-label="Permalink to &quot;三、EPaxos:无 Leader 的 Paxos&quot;">​</a></h2><p>EPaxos 全称 <strong>Egalitarian Paxos</strong>,Iulian Moraru 等人 2013 年提出(<em>There Is More Consensus in Egalitarian Parliaments</em>)。<strong>egalitarian</strong> 意思是「平等的」——<strong>所有节点平等,没有 leader 角色</strong>。</p><h3 id="_3-1-设计动机" tabindex="-1">3.1 设计动机 <a class="header-anchor" href="#_3-1-设计动机" aria-label="Permalink to &quot;3.1 设计动机&quot;">​</a></h3><p>Raft / Multi-Paxos 的 leader 是优化也是瓶颈:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>优点:</span></span>
<span class="line"><span>    leader 接收所有请求,顺序天然确定</span></span>
<span class="line"><span>    follower 只需 append,不需协调</span></span>
<span class="line"><span>    1 RTT 内 commit(假设客户端到 leader 0 RTT)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>缺点:</span></span>
<span class="line"><span>    单点瓶颈:leader 网卡 / CPU 是写吞吐天花板</span></span>
<span class="line"><span>    跨地域延迟:远程 client 必须先 RTT 到 leader,再多数派 RTT</span></span>
<span class="line"><span>    leader 切换:不可用窗口 100-500ms</span></span></code></pre></div><p>EPaxos 的反思:<strong>为什么不允许任何节点直接发起共识?</strong>——只要保证共识仍然安全,<strong>就能让 client 找最近的节点</strong>,延迟最优。</p><h3 id="_3-2-关键观察-不冲突的指令可以乱序" tabindex="-1">3.2 关键观察:不冲突的指令可以乱序 <a class="header-anchor" href="#_3-2-关键观察-不冲突的指令可以乱序" aria-label="Permalink to &quot;3.2 关键观察:不冲突的指令可以乱序&quot;">​</a></h3><p><strong>Raft 强制所有指令排成全序</strong>,但实际上<strong>很多指令是无关的</strong>(不冲突):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>指令 A: SET x = 1</span></span>
<span class="line"><span>指令 B: SET y = 2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>A 和 B 谁先谁后无所谓——它们操作不同的 key,顺序不影响最终状态</span></span></code></pre></div><p><strong>EPaxos 的核心思想</strong>:<strong>只对&quot;冲突的&quot;指令排序</strong>,<strong>不冲突的并行 commit</strong>——这样:</p><ul><li>不冲突:<strong>1 RTT 搞定</strong>(快路径,fast path)</li><li>冲突:<strong>2 RTT 搞定</strong>(慢路径,slow path,要协调)</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                ┌──────────────────────────┐</span></span>
<span class="line"><span>                │  Client 想 commit 指令 I │</span></span>
<span class="line"><span>                └──────────┬───────────────┘</span></span>
<span class="line"><span>                           │</span></span>
<span class="line"><span>                           ▼</span></span>
<span class="line"><span>              ┌──────────────────────────┐</span></span>
<span class="line"><span>              │  本地节点 N 发起 PreAccept │</span></span>
<span class="line"><span>              │  发给所有节点,告知 I 的    │</span></span>
<span class="line"><span>              │  &quot;依赖集 deps&quot;             │</span></span>
<span class="line"><span>              └──────────┬───────────────┘</span></span>
<span class="line"><span>                          │</span></span>
<span class="line"><span>                          ▼</span></span>
<span class="line"><span>              ┌──────────────────────────┐</span></span>
<span class="line"><span>              │  各节点返回自己看到的 deps │</span></span>
<span class="line"><span>              │  N 收集多数派回复          │</span></span>
<span class="line"><span>              └──────────┬───────────────┘</span></span>
<span class="line"><span>                          │</span></span>
<span class="line"><span>            ┌─────────────┴─────────────┐</span></span>
<span class="line"><span>            │                           │</span></span>
<span class="line"><span>   所有回复 deps 相同         有节点 deps 不同</span></span>
<span class="line"><span>   (无冲突)                  (有冲突,要协调)</span></span>
<span class="line"><span>            │                           │</span></span>
<span class="line"><span>            ▼                           ▼</span></span>
<span class="line"><span>   Fast Path                    Slow Path</span></span>
<span class="line"><span>   直接 Commit(1 RTT)         发 Accept(再 1 RTT)</span></span>
<span class="line"><span>                                 → Commit (2 RTT)</span></span></code></pre></div><h3 id="_3-3-冲突检测" tabindex="-1">3.3 冲突检测 <a class="header-anchor" href="#_3-3-冲突检测" aria-label="Permalink to &quot;3.3 冲突检测&quot;">​</a></h3><p>两条指令 I1、I2 <strong>冲突</strong>(interfere)的定义:</p><ul><li>它们访问的 key 集合<strong>有交集</strong></li><li>且至少一个是<strong>写</strong></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SET x = 1 vs SET x = 2          → 冲突(同 key 写)</span></span>
<span class="line"><span>SET x = 1 vs SET y = 2          → 不冲突(不同 key)</span></span>
<span class="line"><span>SET x = 1 vs GET x              → 冲突(写读同 key)</span></span>
<span class="line"><span>GET x vs GET x                  → 不冲突(都是读)</span></span></code></pre></div><p><strong>冲突表现</strong>:不同节点对<strong>冲突指令的依赖关系</strong>可能不一致,<strong>需要协调出统一顺序</strong>。</p><h3 id="_3-4-依赖图-dag-epaxos-的核心结构" tabindex="-1">3.4 依赖图(DAG):EPaxos 的核心结构 <a class="header-anchor" href="#_3-4-依赖图-dag-epaxos-的核心结构" aria-label="Permalink to &quot;3.4 依赖图(DAG):EPaxos 的核心结构&quot;">​</a></h3><p>每条指令 commit 时携带一个 <strong>依赖集 deps</strong>——它&quot;必须排在之后&quot;的所有冲突指令。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>指令 I1: SET x = 1, deps = {}</span></span>
<span class="line"><span>指令 I2: SET y = 2, deps = {}</span></span>
<span class="line"><span>指令 I3: SET x = 3, deps = {I1}     ← I3 依赖 I1</span></span>
<span class="line"><span>指令 I4: SET x = 4, deps = {I1, I3}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>构成 DAG:</span></span>
<span class="line"><span>    I1 ───▶ I3 ───▶ I4</span></span>
<span class="line"><span>    I2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>执行顺序(拓扑序):</span></span>
<span class="line"><span>    I1, I2 可以并行</span></span>
<span class="line"><span>    I3 必须在 I1 之后</span></span>
<span class="line"><span>    I4 必须在 I1 和 I3 之后</span></span></code></pre></div><p><strong>应用到状态机时</strong>:对每条新提交的指令,<strong>做反向 DFS 拓扑排序</strong>,按顺序 apply。<strong>强连通分量(SCC)内部按 seq 排序</strong>(seq 是每个指令的全局递增编号,保证 SCC 内有确定顺序)。</p><h3 id="_3-5-epaxos-的代价" tabindex="-1">3.5 EPaxos 的代价 <a class="header-anchor" href="#_3-5-epaxos-的代价" aria-label="Permalink to &quot;3.5 EPaxos 的代价&quot;">​</a></h3><table tabindex="0"><thead><tr><th>代价</th><th>详情</th></tr></thead><tbody><tr><td><strong>协议实现复杂</strong></td><td>DAG / SCC / 依赖收集 / 冲突分析,代码量是 Raft 的 3-5 倍</td></tr><tr><td><strong>依赖图占内存</strong></td><td>每条指令要存 deps 集合,集群规模大时内存膨胀</td></tr><tr><td><strong>冲突率高时退化</strong></td><td>写均高度冲突(单 key 热点),退化到 2 RTT 比 Raft 还慢</td></tr><tr><td><strong>执行复杂</strong></td><td>不是按 log 顺序 apply,要拓扑排序</td></tr><tr><td><strong>运维难</strong></td><td>无 leader → 没有&quot;主节点&quot;概念,调试和监控习惯都得改</td></tr><tr><td><strong>慢路径需要 N 个 deps 一致</strong></td><td>节点多时 fast path 概率反而降</td></tr></tbody></table><p><strong>EPaxos 的甜区</strong>:</p><ul><li><strong>跨地域 3-5 个节点</strong>(地域多 fast path 价值大)</li><li><strong>写键空间大、冲突率低</strong>(随机 key 范围广)</li><li><strong>关心 P99 而非平均</strong>(不冲突的写 P99 极低)</li></ul><p><strong>反过来</strong>:</p><ul><li><strong>单地域</strong> → leader 0 RTT,EPaxos 完全没优势</li><li><strong>写键集中(热点)</strong> → 冲突率高,slow path 频繁,反而劣于 Raft</li><li><strong>小集群(3 节点)</strong> → fast path 难达成(要 N-1 = 2 个相同 dep,概率不高)</li></ul><h3 id="_3-6-epaxos-工业实现极少" tabindex="-1">3.6 EPaxos 工业实现极少 <a class="header-anchor" href="#_3-6-epaxos-工业实现极少" aria-label="Permalink to &quot;3.6 EPaxos 工业实现极少&quot;">​</a></h3><p><strong>目前公开生产用 EPaxos 的系统几乎为 0</strong>——为什么?</p><ol><li><strong>CockroachDB 早期评估过,最终选了 Raft</strong>——理由是&quot;easier to reason about&quot;</li><li><strong>etcd / Consul / TiKV 全选 Raft</strong>——库成熟,生态好</li><li><strong>少数学术项目和实验性系统用过</strong>:Google 内部某些跨地域服务、Apache Kudu 早期 prototype</li><li><strong>MultiPaxos / Raft 已经够好</strong>——加上 leader transfer + multi-raft + 读优化,<strong>多地域延迟也能压到 50-80ms 级别</strong></li><li><strong>运维成本</strong>:&quot;为了把 P99 从 80ms 降到 50ms,运维复杂度翻 3 倍&quot; → 大多数业务不接受</li></ol><blockquote><p>**EPaxos 是个&quot;理论上更优,工程上跑得动但没人愿意用&quot;**的协议。<strong>它最大的贡献是提醒大家</strong>:<strong>leader 不是必须的,leader-free 在数学上行得通</strong>——这反过来给 Raft 等 leader-based 协议的优化(比如 Multi-Raft + Leader Lease)提供了思路。</p></blockquote><hr><h2 id="四、zab-epaxos-multi-paxos-raft-全对比" tabindex="-1">四、ZAB / EPaxos / Multi-Paxos / Raft 全对比 <a class="header-anchor" href="#四、zab-epaxos-multi-paxos-raft-全对比" aria-label="Permalink to &quot;四、ZAB / EPaxos / Multi-Paxos / Raft 全对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Multi-Paxos</th><th>Raft</th><th>ZAB</th><th>EPaxos</th></tr></thead><tbody><tr><td><strong>Leader 模型</strong></td><td>Distinguished leader</td><td><strong>强 Leader</strong></td><td><strong>强 Leader</strong>(+ FIFO 保证)</td><td><strong>无 Leader</strong>(任何节点发起)</td></tr><tr><td><strong>任期编号</strong></td><td>proposal number(rebid)</td><td>term</td><td>epoch</td><td>ballot number</td></tr><tr><td><strong>日志结构</strong></td><td>可有空洞</td><td><strong>连续无洞</strong></td><td><strong>连续无洞</strong></td><td><strong>DAG</strong>(可并行)</td></tr><tr><td><strong>客户端顺序</strong></td><td>不保证</td><td>不保证</td><td><strong>严格 FIFO</strong></td><td>不保证(乱序 apply)</td></tr><tr><td><strong>正常路径 RTT</strong></td><td>1 RTT(client→leader 不算)</td><td>1 RTT</td><td>1 RTT(+ 1 单向 Commit)</td><td><strong>1 RTT(fast)/ 2 RTT(slow)</strong></td></tr><tr><td><strong>跨地域</strong></td><td>中等</td><td>中等</td><td>中等</td><td><strong>最优(写均匀时)</strong></td></tr><tr><td><strong>成员变更</strong></td><td>Vertical Paxos 后补</td><td><strong>Joint / Single 都有</strong></td><td>后期加 reconfig</td><td>复杂,工业实现少</td></tr><tr><td><strong>典型系统</strong></td><td>Chubby / Spanner / Cassandra LWT</td><td>etcd / Consul / TiKV</td><td>ZooKeeper</td><td>(基本无工业实现)</td></tr><tr><td><strong>可读性</strong></td><td>困难</td><td><strong>极佳</strong></td><td>中等</td><td>困难</td></tr><tr><td><strong>工业接受度</strong></td><td>老牌系统在用</td><td><strong>新系统首选</strong></td><td>ZK 专属</td><td><strong>几乎无</strong></td></tr></tbody></table><blockquote><p><strong>现实选型</strong>:</p><ul><li><strong>不知道选什么 → Raft</strong>(95% 场景)</li><li><strong>写 ZK 兼容协议 / 严格 FIFO 协调 → ZAB</strong></li><li><strong>教科书 / 老 Google 系 → Multi-Paxos</strong></li><li><strong>多地域 + 写均匀 + 实力雄厚的团队 → EPaxos</strong>(但你大概率选 Raft + Multi-Region 优化)</li></ul></blockquote><hr><h2 id="五、zookeeper-的工程现实" tabindex="-1">五、ZooKeeper 的工程现实 <a class="header-anchor" href="#五、zookeeper-的工程现实" aria-label="Permalink to &quot;五、ZooKeeper 的工程现实&quot;">​</a></h2><p>ZK 是 ZAB 唯一的&quot;代言人&quot;,<strong>理解 ZK 的工程现实就是理解 ZAB 的实战</strong>:</p><h3 id="_5-1-zk-的写性能瓶颈" tabindex="-1">5.1 ZK 的写性能瓶颈 <a class="header-anchor" href="#_5-1-zk-的写性能瓶颈" aria-label="Permalink to &quot;5.1 ZK 的写性能瓶颈&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>单个 ZK 集群典型写吞吐:</span></span>
<span class="line"><span>    3 节点:5,000 - 20,000 ops/sec</span></span>
<span class="line"><span>    5 节点:更低(多数派变大)</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>写延迟:</span></span>
<span class="line"><span>    本地集群:1-10ms</span></span>
<span class="line"><span>    跨地域:50-200ms</span></span></code></pre></div><p><strong>瓶颈</strong>:</p><ul><li>所有写过 leader</li><li>多数派 ack(类 Raft)</li><li>ZK 每个事务还要写 WAL(forceSync 默认开启)</li></ul><blockquote><p><strong>不要把 ZK 当 KV 用</strong>——它是协调服务,不是数据库。<strong>写超过几万 QPS 就该考虑 etcd 或别的方案</strong>。</p></blockquote><h3 id="_5-2-zk-的读性能特点" tabindex="-1">5.2 ZK 的读性能特点 <a class="header-anchor" href="#_5-2-zk-的读性能特点" aria-label="Permalink to &quot;5.2 ZK 的读性能特点&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>读默认走任何 follower → 本地内存命中 → 极快(微秒级)</span></span>
<span class="line"><span>读吞吐随节点数线性扩展(读可分散)</span></span></code></pre></div><p><strong>但</strong>:<strong>默认 sequential consistency,可能读到旧值</strong>——<strong>需要强一致读必须 sync()</strong>。</p><h3 id="_5-3-zk-的-watch-机制" tabindex="-1">5.3 ZK 的 watch 机制 <a class="header-anchor" href="#_5-3-zk-的-watch-机制" aria-label="Permalink to &quot;5.3 ZK 的 watch 机制&quot;">​</a></h3><p>每个 znode 可注册 watcher,数据变化通知 client。<strong>这是 ZK 作为协调服务的杀手锏</strong>——但有几个坑:</p><ol><li><strong>One-shot</strong>:每次触发后失效,要重新注册</li><li><strong>可能丢事件</strong>:client 重连期间的事件可能丢失,<strong>ZK 3.6+ 加了 persistent watcher 缓解</strong></li><li><strong>leader 切换时 watcher 重建</strong>:client session 失效会导致 watcher 全部失效</li></ol><blockquote><p><strong>ZK 客户端要时刻准备&quot;重新拿一次状态再注册 watch&quot;</strong>——只信 watch 通知会丢数据。</p></blockquote><h3 id="_5-4-zookeeper-不擅长的事" tabindex="-1">5.4 ZooKeeper 不擅长的事 <a class="header-anchor" href="#_5-4-zookeeper-不擅长的事" aria-label="Permalink to &quot;5.4 ZooKeeper 不擅长的事&quot;">​</a></h3><ul><li><strong>大数据存储</strong>:znode 默认 1MB 上限,<strong>别拿它存任何业务数据</strong></li><li><strong>高频写</strong>:几万 QPS 就开始抖</li><li><strong>大集群</strong>:ZK 集群本身建议 ≤ 7 节点,<strong>节点更多反而吞吐下降</strong>(多数派变大)</li><li><strong>跨地域强一致</strong>:延迟敏感,<strong>ZK observer 模式只能加读副本</strong></li></ul><hr><h2 id="六、epaxos-的理论价值" tabindex="-1">六、EPaxos 的理论价值 <a class="header-anchor" href="#六、epaxos-的理论价值" aria-label="Permalink to &quot;六、EPaxos 的理论价值&quot;">​</a></h2><p>虽然工业落地少,EPaxos 的思想影响了很多后续工作:</p><h3 id="_6-1-multi-paxos-的-无-leader-优化" tabindex="-1">6.1 Multi-Paxos 的&quot;无 leader 优化&quot; <a class="header-anchor" href="#_6-1-multi-paxos-的-无-leader-优化" aria-label="Permalink to &quot;6.1 Multi-Paxos 的&quot;无 leader 优化&quot;&quot;">​</a></h3><p><strong>Mencius / Atlas / Caesar</strong> 等后续协议<strong>继承了 EPaxos 的思想</strong>——多 leader / 旋转 leader,试图在保留 Paxos 简洁性的同时降低跨地域延迟。</p><h3 id="_6-2-影响-crdt-的设计" tabindex="-1">6.2 影响 CRDT 的设计 <a class="header-anchor" href="#_6-2-影响-crdt-的设计" aria-label="Permalink to &quot;6.2 影响 CRDT 的设计&quot;">​</a></h3><p><strong>EPaxos 的&quot;不冲突操作可乱序&quot;思想跟 CRDT 同源</strong>——只是 EPaxos 在共识层做,CRDT 在数据类型层做。详见第 19 篇 CRDT。</p><h3 id="_6-3-影响-multi-raft-的设计" tabindex="-1">6.3 影响 Multi-Raft 的设计 <a class="header-anchor" href="#_6-3-影响-multi-raft-的设计" aria-label="Permalink to &quot;6.3 影响 Multi-Raft 的设计&quot;">​</a></h3><p><strong>Multi-Raft 把数据切分到多个 raft group,每组独立 leader</strong>——这其实是 EPaxos 思想的&quot;工程化分流&quot;:<strong>与其让所有节点都能发起共识,不如让不同 key 范围归不同 leader</strong>,跨地域时让 leader 分散到不同地域。</p><blockquote><p><strong>TiKV / CockroachDB / YugaByte 全用 multi-raft + leader-aware placement</strong>,<strong>用工程手段达到 EPaxos 的部分效果,代价是接受 Raft 的复杂度而非 EPaxos 的复杂度</strong>。</p></blockquote><hr><h2 id="七、共识协议选型框架" tabindex="-1">七、共识协议选型框架 <a class="header-anchor" href="#七、共识协议选型框架" aria-label="Permalink to &quot;七、共识协议选型框架&quot;">​</a></h2><p>我给一个决策树,99% 的场景能套进去:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你的场景是什么?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>├── 需要兼容 ZooKeeper / 已有 ZK 客户端</span></span>
<span class="line"><span>│   └─▶ ZAB(用 ZK 本身)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── 通用 KV / 协调服务 / 配置中心 / 元数据</span></span>
<span class="line"><span>│   ├── 单地域 ────────────▶ Raft(etcd / Consul / 自研)</span></span>
<span class="line"><span>│   └── 跨地域少地域 ──────▶ Raft + multi-raft + leader placement</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── 数据库存储引擎复制</span></span>
<span class="line"><span>│   └── ────────────────────▶ multi-Raft(TiKV / CockroachDB 路线)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── 超大规模 + 极端跨地域 + 实力雄厚</span></span>
<span class="line"><span>│   ├── 选 1:多 region multi-Raft + leader placement(主流)</span></span>
<span class="line"><span>│   └── 选 2:EPaxos / Atlas / SpiderDB(学术 / 自研)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── 老 Google 系 / 已有 Paxos 框架</span></span>
<span class="line"><span>│   └─▶ Multi-Paxos(Chubby 系)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└── 拜占庭场景(联盟链)</span></span>
<span class="line"><span>    └─▶ PBFT / HotStuff / Tendermint(见第 15 篇,不是 Raft 家族)</span></span></code></pre></div><blockquote><p><strong>一个简单原则</strong>:<strong>如果不能立刻说出选 EPaxos / Multi-Paxos 而不是 Raft 的理由,那就选 Raft</strong>。</p></blockquote><hr><h2 id="八、面试常见误区-顺手澄清" tabindex="-1">八、面试常见误区(顺手澄清) <a class="header-anchor" href="#八、面试常见误区-顺手澄清" aria-label="Permalink to &quot;八、面试常见误区(顺手澄清)&quot;">​</a></h2><h3 id="_8-1-「zk-是用-paxos-实现的」" tabindex="-1">8.1 「ZK 是用 Paxos 实现的」 <a class="header-anchor" href="#_8-1-「zk-是用-paxos-实现的」" aria-label="Permalink to &quot;8.1 「ZK 是用 Paxos 实现的」&quot;">​</a></h3><p><strong>错</strong>。ZK 用 ZAB,<strong>ZAB 跟 Paxos 同族但不同协议</strong>。论文里 ZAB 作者明确说&quot;ZAB 不是 Paxos&quot;——它有独立的安全性证明。</p><h3 id="_8-2-「raft-是-paxos-的子集」" tabindex="-1">8.2 「Raft 是 Paxos 的子集」 <a class="header-anchor" href="#_8-2-「raft-是-paxos-的子集」" aria-label="Permalink to &quot;8.2 「Raft 是 Paxos 的子集」&quot;">​</a></h3><p><strong>部分对</strong>。Raft 的算法可以看作&quot;约束更多的 Multi-Paxos&quot;,但<strong>Raft 重新组织了证明结构,有独立的不变量体系</strong>。说&quot;子集&quot;忽略了它的可读性贡献。</p><h3 id="_8-3-「epaxos-因为复杂-所以错了」" tabindex="-1">8.3 「EPaxos 因为复杂,所以错了」 <a class="header-anchor" href="#_8-3-「epaxos-因为复杂-所以错了」" aria-label="Permalink to &quot;8.3 「EPaxos 因为复杂,所以错了」&quot;">​</a></h3><p><strong>不对</strong>。EPaxos 在数学上完全正确,<strong>没有任何 Jepsen 级别的 bug 报告</strong>(因为没人在生产用)。它只是&quot;工程上不被接受&quot;——这是不同维度。</p><h3 id="_8-4-「zk-提供线性一致性」" tabindex="-1">8.4 「ZK 提供线性一致性」 <a class="header-anchor" href="#_8-4-「zk-提供线性一致性」" aria-label="Permalink to &quot;8.4 「ZK 提供线性一致性」&quot;">​</a></h3><p><strong>只对写</strong>。<strong>ZK 默认读是 sequential</strong>,需要 linearizable 要 sync()。<strong>这是面试最容易答错的一点</strong>。</p><hr><h2 id="九、真实系统映射" tabindex="-1">九、真实系统映射 <a class="header-anchor" href="#九、真实系统映射" aria-label="Permalink to &quot;九、真实系统映射&quot;">​</a></h2><table tabindex="0"><thead><tr><th>协议</th><th>系统</th><th>备注</th></tr></thead><tbody><tr><td><strong>ZAB</strong></td><td>ZooKeeper</td><td>唯一工业代表</td></tr><tr><td><strong>类 ZAB</strong></td><td>Apache Curator(ZK 客户端封装)</td><td>用 ZK,保留 ZAB 语义</td></tr><tr><td><strong>EPaxos / 类 EPaxos</strong></td><td>学术原型 / 少数 Google 内部 / SpiderDB(已停)</td><td>工业落地极少</td></tr><tr><td><strong>Multi-Paxos</strong></td><td>Chubby / Spanner / Cassandra LWT</td><td>Google + 数据库</td></tr><tr><td><strong>Raft</strong></td><td>etcd / Consul / TiKV / CockroachDB / KRaft / 各种自研</td><td>新系统首选</td></tr></tbody></table><blockquote><p><strong>ZK 没死</strong>——它在 Hadoop / HBase / Kafka(旧版) / Solr / Flink JM 选主 / Spark 早期都广泛使用。但<strong>Kafka 3.3+ 用 KRaft 替了 ZK,Pulsar 用 BookKeeper 不依赖 ZK,Flink 趋势也在去 ZK</strong>。<strong>ZK 是 Hadoop 时代的协调服务王者,但新时代正在被 Raft + etcd 替代</strong>。</p></blockquote><hr><h2 id="十、踩坑提醒" tabindex="-1">十、踩坑提醒 <a class="header-anchor" href="#十、踩坑提醒" aria-label="Permalink to &quot;十、踩坑提醒&quot;">​</a></h2><ol><li><strong>以为 ZK 默认读是强一致</strong>——<strong>默认 sequential,要 sync()</strong>;<strong>用 ZK 实现锁、读锁状态时必须 sync(),否则可能误判</strong></li><li><strong>用 ZK 当数据库</strong>——ZK znode 默认 1MB 上限,<strong>几万写就抖,别拿它存业务数据</strong></li><li><strong>ZK 集群规模太大</strong>(&gt; 7 节点)——<strong>多数派变大,吞吐反而下降</strong>,典型部署 3 / 5 节点</li><li><strong>跨地域部署 ZK</strong>——延迟敏感,<strong>ZK 跨机房延迟超 50ms 就要重新评估</strong>,要么用 observer,要么换方案</li><li><strong>不处理 ZK 的 session 失效</strong>——network partition 导致 client session 超时,<strong>所有 ephemeral node 消失、watch 失效</strong>;<strong>客户端必须有重连 + 重建状态的逻辑</strong></li><li><strong>以为 EPaxos 比 Raft 更好就上 EPaxos</strong>——<strong>实现复杂度 3-5 倍</strong>,<strong>没有成熟开源库</strong>,<strong>99% 的项目应该用 Raft</strong></li><li><strong>EPaxos 在高冲突场景下用</strong>——<strong>冲突率高时 slow path 频繁,反而比 Raft 慢</strong>;只在写均匀(随机大 keyspace)时才有优势</li><li><strong>不理解 ZAB FIFO 语义</strong>——<strong>ZK client API 的&quot;顺序保证&quot;来自 ZAB,换 etcd 后没有这个保证</strong>,业务要自己做 sequencing</li><li><strong>混淆 ZAB epoch 和 Raft term</strong>——概念类似,<strong>实现细节不同</strong>(zxid 把 epoch 编进事务 ID,Raft 把 term 放在每条 entry)</li><li><strong>EPaxos 的依赖图不持久化</strong>——崩溃恢复后依赖图丢失,EPaxos 的依赖<strong>必须随日志一起持久化</strong>;部分实现里这是 bug 源头</li><li><strong>以为「无 leader = 更可用」</strong>——<strong>EPaxos 同样需要多数派,少数派依然不可写</strong>;无 leader 不等于无多数派依赖</li></ol><hr><h2 id="十一、收束" tabindex="-1">十一、收束 <a class="header-anchor" href="#十一、收束" aria-label="Permalink to &quot;十一、收束&quot;">​</a></h2><p>ZAB 和 EPaxos 是共识协议家族的&quot;另一面&quot;:</p><ul><li><strong>ZAB 教会我们:协议可以为特定应用语义定制——严格 FIFO + 协调服务,ZK 用 ZAB 不用 Raft 的原因就是历史早 + 语义更贴合</strong>。</li><li><strong>EPaxos 教会我们:leader 不是必须的——leader-free 数学上可行,只是工程上太贵</strong>。</li></ul><p><strong>Raft 不是终点,Raft 是当前最优解</strong>——它在「易实现 / 易理解 / 性能足够」三角上取得了最佳平衡。<strong>ZAB 在 Hadoop 时代有它的辉煌,EPaxos 是学术界对 Paxos 家族的最后一次重大革新</strong>——它们都是共识理论这棵大树的旁枝,<strong>主干仍然是 Multi-Paxos → Raft 这条线</strong>。</p><p>下一篇我们将彻底离开「诚实节点」的世界,进入<strong>拜占庭故障</strong>——<strong>节点可以撒谎、可以攻击、可以任意行为</strong>。<strong>Raft / ZAB / EPaxos 全部失效,要换一套完全不同的协议</strong>——PBFT、HotStuff、Tendermint,<strong>这是区块链共识的根基,也是金融级容灾的天花板</strong>。</p><blockquote><p><strong>看完这篇,你应该能在脑子里清楚回答</strong>:<strong>ZK 为什么不能改成 Raft 复制(语义不兼容)?EPaxos 为什么不流行(实现太难,Raft 已够用)?Raft + multi-region 怎么近似 EPaxos 的多地域优势(multi-raft + leader placement)?</strong> 能想清这三问,你就吃透了共识协议家族 95% 的工程图景。</p></blockquote><hr><p>下一篇:<code>15-拜占庭容错.md</code>,<strong>进入&quot;节点可以撒谎&quot;的世界</strong>——为什么 N ≥ 3f+1、PBFT 三阶段为什么是 O(N²) 消息、HotStuff 怎么把它降到 O(N)、Tendermint / Cosmos 怎么把 PBFT 和 PoS 结合,<strong>为什么 99% 的业务不需要 BFT</strong>——内网集群 Raft / Paxos 完全够用,<strong>BFT 是 3-5 倍开销的奢侈品</strong>。</p>`,148)])])}const u=a(e,[["render",r]]);export{h as __pageData,u as default};
